// portfolio/client/src/components/ReviewCard.jsx
import React from 'react';
import { motion } from 'framer-motion';

const ReviewCard = ({ review, index }) => {
  // Generate a stable avatar based on name
  const getAvatar = (name) => {
    const colors = ['#06b6d4', '#8b5cf6', '#ec4899', '#f59e0b', '#10b981', '#3b82f6'];
    const colorIndex = name.charCodeAt(0) % colors.length;
    const initials = name.split(' ').map(n => n[0]).join('').toUpperCase();
    return { initials, color: colors[colorIndex] };
  };

  const avatar = getAvatar(review.name);
  const formatDate = (date) => {
    const d = new Date(date);
    return d.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
  };

  const renderStars = (rating) => {
    return (
      <div style={{ display: 'flex', gap: '4px' }}>
        {[...Array(5)].map((_, i) => (
          <span key={i} style={{ color: i < rating ? '#fbbf24' : 'rgba(6,182,212,0.2)', fontSize: '1.1rem' }}>
            ★
          </span>
        ))}
      </div>
    );
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: 20 }}
      transition={{ duration: 0.5, delay: index * 0.1 }}
      viewport={{ once: true, margin: '-100px' }}
      whileHover={{ y: -8, transition: { duration: 0.2 } }}
      style={{
        background: 'rgba(15, 31, 61, 0.7)',
        border: '1px solid rgba(6, 182, 212, 0.12)',
        borderRadius: '14px',
        padding: '24px',
        backdropFilter: 'blur(10px)',
        transition: 'border-color 0.3s ease, box-shadow 0.3s ease',
        cursor: 'pointer',
        position: 'relative',
        overflow: 'hidden'
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.borderColor = 'rgba(6, 182, 212, 0.35)';
        e.currentTarget.style.boxShadow = '0 8px 32px rgba(6, 182, 212, 0.1)';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.borderColor = 'rgba(6, 182, 212, 0.12)';
        e.currentTarget.style.boxShadow = 'none';
      }}
    >
      {/* Gradient accent on top */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        height: '2px',
        background: 'linear-gradient(90deg, transparent, var(--cyan), transparent)'
      }} />

      {/* Header with avatar, name, and rating */}
      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: '16px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1 }}>
          {/* Avatar */}
          <div
            style={{
              width: '44px',
              height: '44px',
              borderRadius: '10px',
              background: avatar.color,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'white',
              fontWeight: 'bold',
              fontSize: '1rem',
              flexShrink: 0,
              opacity: 0.85
            }}
          >
            {avatar.initials}
          </div>

          {/* Name and Company */}
          <div style={{ minWidth: 0, flex: 1 }}>
            <div style={{ fontWeight: '600', fontSize: '0.95rem', color: 'var(--text-primary)', marginBottom: '2px' }}>
              {review.name}
            </div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
              {review.company || 'Client'}
            </div>
          </div>
        </div>

        {/* Rating */}
        <div style={{ textAlign: 'right' }}>
          {renderStars(review.rating)}
        </div>
      </div>

      {/* Review message */}
      <p style={{
        fontSize: '0.92rem',
        lineHeight: 1.6,
        color: 'var(--text-secondary)',
        marginBottom: '14px',
        fontStyle: 'italic',
        borderLeft: '2px solid rgba(6, 182, 212, 0.2)',
        paddingLeft: '12px'
      }}>
        "{review.message}"
      </p>

      {/* Date */}
      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
        {formatDate(review.createdAt)}
      </div>
    </motion.div>
  );
};

export default ReviewCard;
